def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    result = []
    start = nums[0]

    for i in range(1, len(nums)):
        if nums[i] != nums[i-1] + 1:
            if start == nums[i-1]:
                result.append(str(start))
            else:
                result.append(f"{start}-{nums[i-1]}")
            start = nums[i]

    # Append the last range
    if start == nums[-1]:
        result.append(str(start))
    else:
        result.append(f"{start}-{nums[-1]}")

    return ', '.join(result)
